!function(){const init=()=>{document.querySelectorAll('[data-bs-toggle="tooltip"]').forEach(e=>{const t=bootstrap.Tooltip.getOrCreateInstance(e,{container:"body"});let o;e.addEventListener("shown.bs.tooltip",()=>{clearTimeout(o),o=setTimeout(()=>{t.hide()},3e3)}),e.addEventListener("hide.bs.tooltip",()=>{clearTimeout(o)}),e.addEventListener("hidden.bs.tooltip",()=>{clearTimeout(o)})})};"loading"===document.readyState?document.addEventListener("DOMContentLoaded",init,{once:!0}):init()}();